package com.lightevents.payments;
import jakarta.persistence.*; import java.math.BigDecimal; import java.time.Instant; import java.util.UUID;
@Entity @Table(name="transactions")
public class Transaction { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; private String reference=UUID.randomUUID().toString(); private Long eventId; private Long attendeeId; private String reservationReference; @Enumerated(EnumType.STRING) private PaymentProvider provider; @Enumerated(EnumType.STRING) private PaymentStatus status=PaymentStatus.INITIATED; private BigDecimal amount; private BigDecimal platformFee=BigDecimal.ZERO; private BigDecimal organizerNet=BigDecimal.ZERO; private String currency="XOF"; private String payerPhone; @Column(length=1200) private String checkoutUrl; private String providerReference; private String organizerPayoutMethod; @Column(length=1200) private String organizerPayoutAccountRef; private String payoutStatus="PENDING"; private Instant createdAt=Instant.now(); public Long getId(){return id;} public String getReference(){return reference;} public Long getEventId(){return eventId;} public void setEventId(Long v){eventId=v;} public Long getAttendeeId(){return attendeeId;} public void setAttendeeId(Long v){attendeeId=v;} public String getReservationReference(){return reservationReference;} public void setReservationReference(String v){reservationReference=v;} public PaymentProvider getProvider(){return provider;} public void setProvider(PaymentProvider v){provider=v;} public PaymentStatus getStatus(){return status;} public void setStatus(PaymentStatus v){status=v;} public BigDecimal getAmount(){return amount;} public void setAmount(BigDecimal v){amount=v;} public BigDecimal getPlatformFee(){return platformFee;} public void setPlatformFee(BigDecimal v){platformFee=v;} public BigDecimal getOrganizerNet(){return organizerNet;} public void setOrganizerNet(BigDecimal v){organizerNet=v;} public String getCurrency(){return currency;} public void setCurrency(String v){currency=v;} public String getPayerPhone(){return payerPhone;} public void setPayerPhone(String v){payerPhone=v;} public String getCheckoutUrl(){return checkoutUrl;} public void setCheckoutUrl(String v){checkoutUrl=v;} public String getProviderReference(){return providerReference;} public void setProviderReference(String v){providerReference=v;} public String getOrganizerPayoutMethod(){return organizerPayoutMethod;} public void setOrganizerPayoutMethod(String v){organizerPayoutMethod=v;} public String getOrganizerPayoutAccountRef(){return organizerPayoutAccountRef;} public void setOrganizerPayoutAccountRef(String v){organizerPayoutAccountRef=v;} public String getPayoutStatus(){return payoutStatus;} public void setPayoutStatus(String v){payoutStatus=v;} public Instant getCreatedAt(){return createdAt;} }
